{
  "mode": "io",
  "tests": [
    {
      "name": "list_challenges_user",
      "input": "{\"action\": \"list_challenges\", \"user_type\": \"USER\"}",
      "output": "{\"challenges\": [\"TC-002-COPILOT\", \"TC-002-USER\"]}",
      "notes": "Validates the retrieval of challenges for a USER."
    },
    {
      "name": "create_challenges_admin",
      "input": "{\"action\": \"create_challenge\", \"user_type\": \"ADMIN\", \"challenge_data\": {\"name\": \"New Challenge\"}}",
      "output": "{\"status\": \"success\", \"challenge_id\": \"TC-006-ADMIN\"}",
      "notes": "Tests the creation of a challenge by an ADMIN."
    },
    {
      "name": "get_challenges_user",
      "input": "{\"action\": \"get_challenges\", \"user_type\": \"USER\"}",
      "output": "{\"challenges\": [\"TC-020-USER\", \"TC-021-USER\"]}",
      "notes": "Checks if USER can retrieve challenges."
    },
    {
      "name": "update_challenge_admin",
      "input": "{\"action\": \"update_challenge\", \"user_type\": \"ADMIN\", \"challenge_id\": \"PUT-001-ADM\", \"update_data\": {\"status\": \"active\"}}",
      "output": "{\"status\": \"updated\", \"challenge_id\": \"PUT-001-ADM\"}",
      "notes": "Ensures an ADMIN can update a challenge."
    },
    {
      "name": "get_challenge_statistics",
      "input": "{\"action\": \"get_statistics\", \"challenge_id\": \"STAT-TC-001\"}",
      "output": "{\"statistics\": {\"views\": 100, \"submissions\": 10}}",
      "notes": "Validates retrieval of statistics for a specific challenge."
    },
    {
      "name": "post_challenge_notification",
      "input": "{\"action\": \"post_notification\", \"user_type\": \"ADMIN\", \"notification_data\": {\"message\": \"New Challenge Created\"}}",
      "output": "{\"status\": \"notification_sent\"}",
      "notes": "Tests posting a notification by an ADMIN."
    },
    {
      "name": "edge_case_invalid_user",
      "input": "{\"action\": \"list_challenges\", \"user_type\": \"INVALID\"}",
      "output": "{\"error\": \"Invalid user type\"}",
      "notes": "Tests response to an invalid user type."
    },
    {
      "name": "edge_case_empty_challenge_data",
      "input": "{\"action\": \"create_challenge\", \"user_type\": \"ADMIN\", \"challenge_data\": {}}",
      "output": "{\"error\": \"Challenge data cannot be empty\"}",
      "notes": "Validates error handling for empty challenge data."
    }
  ],
  "assumptions": "All user types and actions are predefined and valid.",
  "notes": "Ensure that the API is running and accessible during testing."
}
